[
  {
    "id": "start",
    "type": "start",
    "name": "Start Workflow",
    "description": "Initiates the server status check and restart workflow.",
    "next_step": "check_server_status"
  },
  {
    "id": "check_server_status",
    "type": "action",
    "name": "Check Server Status",
    "description": "Executes a command to check the status of 'web-prod-01'.",
    "action": {
      "command": "ssh user@web-prod-01 'systemctl is-active apache2'",
      "output_variable": "server_status_output",
      "expected_output": "active"
    },
    "next_step_on_success": "notify_success",
    "next_step_on_failure": "restart_server"
  },
  {
    "id": "restart_server",
    "type": "action",
    "name": "Restart Server",
    "description": "Restarts 'web-prod-01' if it was found to be down.",
    "action": {
      "command": "ssh user@web-prod-01 'sudo systemctl restart apache2'",
      "output_variable": "restart_output"
    },
    "next_step_on_success": "verify_restart",
    "next_step_on_failure": "notify_restart_failure"
  },
  {
    "id": "verify_restart",
    "type": "action",
    "name": "Verify Server Restart",
    "description": "Re-checks the status of 'web-prod-01' after a restart attempt.",
    "action": {
      "command": "ssh user@web-prod-01 'systemctl is-active apache2'",
      "output_variable": "verify_status_output",
      "expected_output": "active"
    },
    "next_step_on_success": "notify_restart_success",
    "next_step_on_failure": "notify_restart_failure"
  },
  {
    "id": "notify_success",
    "type": "notification",
    "name": "Notify Server Active",
    "description": "Sends an email notification that 'web-prod-01' is active.",
    "notification": {
      "method": "email",
      "to": "admin@example.com",
      "subject": "Server 'web-prod-01' is Active",
      "body": "Server 'web-prod-01' is currently running and active."
    },
    "next_step": "end"
  },
  {
    "id": "notify_restart_success",
    "type": "notification",
    "name": "Notify Server Restarted",
    "description": "Sends an email notification that 'web-prod-01' was restarted successfully.",
    "notification": {
      "method": "email",
      "to": "admin@example.com",
      "subject": "Server 'web-prod-01' Restarted Successfully",
      "body": "Server 'web-prod-01' was found down and has been successfully restarted."
    },
    "next_step": "end"
  },
  {
    "id": "notify_restart_failure",
    "type": "notification",
    "name": "Notify Restart Failure",
    "description": "Sends an email notification that 'web-prod-01' failed to restart.",
    "notification": {
      "method": "email",
      "to": "admin@example.com",
      "subject": "CRITICAL: Server 'web-prod-01' Restart Failed",
      "body": "Server 'web-prod-01' was found down and an attempt to restart it failed. Manual intervention required. Restart output: ${restart_output}. Verification output: ${verify_status_output}."
    },
    "next_step": "end"
  },
  {
    "id": "end",
    "type": "end",
    "name": "End Workflow",
    "description": "Marks the completion of the workflow."
  }
]

